SELECT class_name 
FROM crop_classes 
WHERE class_id = 0;

SELECT observation_id
FROM ground_truth_data
WHERE observer_id = 0 AND crop_id = 'specific_class_id';

SELECT class_id, class_name
FROM crop_classes
WHERE class_id NOT IN (SELECT crop_id FROM ground_truth_data);

SELECT source_name, source_type
FROM data_sources
WHERE source_id IN (SELECT data_id FROM analysis_reports);

SELECT DISTINCT user_name, affiliation
FROM users
WHERE user_id IN (
  SELECT observer_id
  FROM ground_truth_data
);

SELECT class_name
FROM crop_classes
WHERE class_id IN (SELECT crop_id FROM ground_truth_data);

SELECT DISTINCT UNICODE(common_name) 
FROM crop_classes 
WHERE class_id > 0;
